import React, { memo, useRef, useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from "classnames";
import styles from './StarContainer.module.scss';
import { debounce } from "debounce";
import { MAX_WIDTH, MAX_HEIGHT, MOBILE_BREAKPOINT } from "../../constants/constants";
import CustomPopover from "../Popover";

const StarContainer = (props) => {
    const { name, group, x, y, id, isHovered, setHoverGroup, transformParam, setCoordinates, drawNumber } = props;
    const ref = useRef();
    const [anchorEl, setAnchorEl] = useState(null);
    const open = !!anchorEl;

    /**
     *@description Change main hover group state when mouseEnter event
     */
    const handleMouseEnter = () => {
        setHoverGroup(group);
    }

    /**
     *@description Change main hover group state to null when mouseLeave event
     */
    const handleMouseLeave = () => {
        setHoverGroup(null);
    }

    /**
     * @description Open popover
     * @param e {Event}
     */
    const handleClick = (e) => {
        setAnchorEl(e.currentTarget);
    }

    /**
     * @description Close popover
     */
    const handleClose = () => {
        setAnchorEl(null);
    };

    /**
     * Set star coordinates. Used to draw the stars sector;
     */
    const setHoverParam = () => {
        const { x: clientX, y: clientY } = ref.current.getBoundingClientRect(); // get positions params of star
        setCoordinates(state => {
            const newState = [...state];
            const index = newState.findIndex(item => item.id === id);

            // Need small correction of coordinates when draw sector (because of using canvas)
            const correctionX = window?.innerWidth > MAX_WIDTH ? ((window?.innerWidth - MAX_WIDTH) / 2) + 70 : 70;
            const correctionY = window?.innerHeight > MAX_HEIGHT && window?.innerWidth > MOBILE_BREAKPOINT ? ((window?.innerHeight - MAX_HEIGHT) / 2) + 170 : 170;

            if (index > -1) { // update star param
                newState[index] = { drawNumber, clientX: clientX - correctionX, clientY: clientY - correctionY, group, id }
            } else { // create new star param
                newState.push({ drawNumber, clientX: clientX - correctionX, clientY: clientY - correctionY, group, id });
            }
            return newState;
        })
    }

    /**
     * Set star coordinates when resize. Used to draw the stars sector; (another correctionX and correctionY)
     */
    const setResizeHoverParam = debounce(() => {
        const { x: clientX, y: clientY } = ref.current.getBoundingClientRect();
        setCoordinates(state => {
            const newState = [...state];
            const index = newState.findIndex(item => item.id === id);
            const correctionX = window?.innerWidth > MAX_WIDTH ? ((window?.innerWidth - MAX_WIDTH) / 2) - 65 : 30;
            const correctionY = window?.innerHeight > MAX_HEIGHT && window?.innerWidth > MOBILE_BREAKPOINT ? ((window?.innerHeight - MAX_HEIGHT) / 2) - 20 : 30;

            if (index > -1) {
                newState[index] = { drawNumber, clientX: clientX + correctionX, clientY: clientY + correctionY, group, id }
            } else {
                newState.push({ drawNumber, clientX: clientX + correctionX, clientY: clientY + correctionY, group, id });
            }
            return newState;
        })
    }, 10);

    useEffect(() => {
        window.addEventListener('resize', setResizeHoverParam)

        return () => {
            window.removeEventListener('resize', setResizeHoverParam)
        };
    }, [])

    useEffect(() => {
        setHoverParam();
    }, [ref]);

    // If N/D type - disabled star
    if (group === 'N/D') {
        return (
            <div className={styles.root} style={{ gridArea: `${y} / ${x}` }}>
                <div className={classNames(styles.wrapper, styles.disabled)} ref={ref} id={`id${id}`}>
                    <button className={classNames(styles.star, styles.disabled)}/>
                    <span key={group}>{group}</span>
                </div>
            </div>
      );
    }

    return (
        <>
        <div className={styles.root} style={{ gridArea: `${y} / ${x}` }}>
            <div className={classNames(styles.wrapper, {[styles.hovered]: open })} ref={ref} id={`id${id}`}>
                <button className={classNames(styles.star, {[styles.hovered]: open })} onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseLeave} onClick={handleClick}/>
                <span key={name}>{name}</span>
                <span key={group}>{group}</span>
            </div>
        </div>
            <CustomPopover
                name={name}
                group={group}
                open={open}
                anchorEl={anchorEl}
                onClose={handleClose}
                transitionDuration={0}
                anchorOrigin={{
                    vertical: 'bottom',
                    horizontal: 'center',
                }}
                transformOrigin={{
                    vertical: 'top',
                    horizontal: 'center',
                }}
            />
        </>
    );
};

StarContainer.propTypes = {
    name: PropTypes.string.isRequired,
    group: PropTypes.string.isRequired,
    id: PropTypes.string.isRequired,
    drawNumber: PropTypes.number.isRequired,
    x: PropTypes.number.isRequired,
    y: PropTypes.number.isRequired,
    isHovered: PropTypes.bool.isRequired,
    setHoverGroup: PropTypes.func.isRequired,
    transformParam: PropTypes.object.isRequired,
    setCoordinates: PropTypes.func.isRequired,
};

StarContainer.defaultProps = {};

export default memo(StarContainer);
