import React, {useState, useRef} from 'react';
import styles from './StarsRoot.module.scss';
import Grid from "../Grid";
import PrismaZoom from 'react-prismazoom'

const StarsRoot = () => {
    const ref = useRef(null);
    const [zoom, setZoom] = useState(1);

    const handleZoomIn = () => {
        ref.current.zoomIn();
    }

    const handleZoomOut = () => {
        ref.current.zoomOut();
    }

    const handleZoomChange = (zoom) => setZoom(zoom);

    return (
        <div className={styles.wrapper}>
            <div className={styles.root}>

                            <div className={styles.tools}>
                                <button onClick={handleZoomIn} disabled={+zoom >= 4}>+</button>
                                <button onClick={handleZoomOut} disabled={+zoom <= 1}>-</button>
                            </div>

                <PrismaZoom ref={ref} onZoomChange={handleZoomChange} maxZoom={4}>
                        <Grid transformParam={{}} stars={stars} />
                </PrismaZoom>

            </div>
        </div>
    );
};

StarsRoot.propTypes = {};

StarsRoot.defaultProps = {};

export default StarsRoot;


