import React, {useEffect, useRef, useState} from 'react';
import PropTypes from 'prop-types';
import styles from './Canvas.module.scss';
import { MAX_WIDTH, MAX_HEIGHT, MOBILE_BREAKPOINT, GRID_STEP } from "../../constants/constants";
import { debounce } from "debounce";

const Canvas = (props) => {
    const { hoverGroup, coordinates } = props;
    const ref = useRef();
    const [param, setParam] = useState({ width: 0, height: 0});

    /**
     * @description Draw stars sector by coordinates
     */
    const drawSector = () => {
        if (hoverGroup) { // draw sector i hoverGroup !== null
            const activeSector = [...coordinates].filter(item => item.group === hoverGroup); // filer only active hover group stars
            activeSector.sort((a, b) => +a.drawNumber - +b.drawNumber); // sort by draw number (its important to keep drawing order)

            const ctx = ref.current.getContext('2d');
            ctx.fillStyle = 'rgba(255,255,255,0.1)';
            ctx.strokeStyle = 'rgba(255,255,255,0.3)';
            ctx.beginPath();
            ctx.moveTo(activeSector[0]?.clientX,activeSector[0]?.clientY);
            for (let i = 1; i <= activeSector.length; i++) {
                ctx.lineTo(activeSector[i]?.clientX, activeSector[i]?.clientY);
            }
            ctx.lineTo(activeSector[0]?.clientX,activeSector[0]?.clientY);
            ctx.stroke();
            ctx.fill();
        } else {
            drawGrid(); // draw only grid if hoverGroup === null
        }
    }

    // useEffect(() => {
    //     drawSector();
    // }, [hoverGroup]);

    /**
     * Draw grid :)
     */
    const drawGrid = () => {
        const width =  window.innerWidth > MAX_WIDTH ? MAX_WIDTH : window.innerWidth;
        const height = window.innerHeight > MAX_HEIGHT && window.innerWidth > MOBILE_BREAKPOINT ? MAX_HEIGHT : window.innerHeight;

        const ctx = ref.current.getContext('2d');
        ctx.clearRect(0,0, width, height);
        ctx.strokeStyle = '#222222';
        ctx.lineWidth = 1;


        const drawHeightLine = (value) => {
            ctx.beginPath();
            ctx.moveTo(0, value);
            ctx.lineTo(width, value);
            ctx.stroke();
        }

        const drawWidthLine = (value) => {
            ctx.beginPath();
            ctx.moveTo(value, 0);
            ctx.lineTo(value, height);
            ctx.stroke();
        }

        for (let i = GRID_STEP; i < height; i += GRID_STEP) {
            drawHeightLine(i);
        }

        for (let i = GRID_STEP; i < width; i += GRID_STEP) {
            drawWidthLine(i);
        }
    }

    // Change canvas width and height when resize (need it to draw correct grid)
    const onResize =  debounce(() => {
        const width =  window.innerWidth > MAX_WIDTH ? MAX_WIDTH : window.innerWidth;
        const height = window.innerHeight > MAX_HEIGHT && window.innerWidth > MOBILE_BREAKPOINT ? MAX_HEIGHT : window.innerHeight;
        setParam({ width, height })
    }, 20);

    useEffect(() => {
        onResize();
        window.addEventListener('resize', onResize);
        return () => {
            window.removeEventListener('resize', onResize);
        };
    }, []);

    // Draw grid when param change
    useEffect(() => {
        drawGrid();
    }, [param]);

    useEffect(() => {
        drawGrid();
    }, [])

    return (
  <div className={styles.root}>
      <div className={styles.canvas}>
          <canvas ref={ref} width={param.width} height={param.height}/>
      </div>
  </div>
    );
};

Canvas.propTypes = {
    hoverGroup: PropTypes.string.isRequired,
    coordinates: PropTypes.array.isRequired,
};

Canvas.defaultProps = {};

export default Canvas;
