/**
 * @description Return max y and max x value
 * @param array {[{x: number, y: number}]}
 * @returns {{xLength: number, yLength: number}}
 */
const checkGridSize = (array) => {
    if (!Array.isArray(array)) {
        throw new Error('checkGridSize error: Argument must be an array');;
    }

    const xArray = [];
    const yArray = [];

    array.forEach(({ x, y }) => {
        xArray.push(x);
        yArray.push(y);
    })

    const values = {};

    values.xLength = Math.max.apply(null, xArray);
    values.yLength = Math.max.apply(null, yArray);
    // values.cellSize = window?.innerWidth / values.xLength
    // values.xWidth = values.xLength * size;
    // values.yWidth = values.yLength * size;

    return values;
}

export default checkGridSize;
